module.exports = function(RED) {
    function EntreesNode(config) {
        RED.nodes.createNode(this, config);
        var node = this;

        node.name = config.name;
        try {
            node.elements = JSON.parse(config.elements || "[]");
        } catch(e) {
            node.elements = [];
        }

        node.on('input', function(msg) {
            node.send(null);
        });
    }
    RED.nodes.registerType("entrees", EntreesNode);
}
